import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build maps: (project_basename, framework, package_id) -> resolved_version
def build_map(data):
    m = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return m

bm = build_map(baseline)
am = build_map(after)

all_keys = sorted(set(bm.keys()) | set(am.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = bm.get(k)
    av = am.get(k)
    if bv is None:
        changes.append((k[0], k[1], k[2], '-', av, 'Added'))
    elif av is None:
        changes.append((k[0], k[1], k[2], bv, '-', 'Removed'))
    elif bv != av:
        changes.append((k[0], k[1], k[2], bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]:20s} {c[1]:10s} {c[2]:50s} {c[3]:10s} -> {c[4]:10s} ({c[5]})')
else:
    print('None')

print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'{u[0]:20s} {u[1]:10s} {u[2]:50s} {u[3]}')
"

